16	const ITEM_TYPE_SEARCH_LIMIT = 8;
17	const ITEM_NUMBER_GENERATION_MAX_ATTEMPTS = 25;
18	const LICENSOR_MERCH_GROUP_TYPE = '05';
19	const PROPERTY_MERCH_GROUP_TYPE = '06';
