29	const buildItemTypeSearchWhereClause = (query = '') => {
30	  const searchTerms = getItemTypeSearchTerms(query);
31	  const baseWhereClause = {
32	    item_type_status: 'ACTIVE'
33	  };
34	
35	  if (!searchTerms.length) {
36	    return baseWhereClause;
37	  }
38	
39	  return {
40	    ...baseWhereClause,
41	    [Op.or]: searchTerms.flatMap((term) => ([
42	      { item_type_name: { [Op.iLike]: `%${term}%` } },
43	      { item_type_description: { [Op.iLike]: `%${term}%` } }
44	    ]))
45	  };
46	};
47	
48	const parseDivisionCodes = (value) => {
49	  if (value === undefined || value === null || value === '') {
50	    return [];
51	  }
52	
53	  const rawValues = Array.isArray(value) ? value : String(value).split(',');
54	  return rawValues
55	    .map((item) => Number(item))
56	    .filter((item) => Number.isFinite(item));
57	};
