59	const mapMerchGroupOption = (row) => ({
60	  id: row.mg_id,
61	  title: row.mg_desc,
62	  mg_code: row.mg_code,
63	  parent_id: row.parent_id,
64	  divisionCode: row.divisionCode_id_fk,
65	  mgCode2: row.mgCode2,
66	  mgCategory: row.mgCategory,
67	});
