69	ItemLibrary.getLicensorsWithProperties = async (req, result) => {
70	  try {
71	    const divisionCodes = parseDivisionCodes(req.query?.divisionCode ?? req.body?.divisionCode);
72	    const propertyWhereClause = {
73	      is_active: true,
74	      mgTypeCode: PROPERTY_MERCH_GROUP_TYPE,
75	    };
76	
77	    if (divisionCodes.length) {
78	      propertyWhereClause.divisionCode_id_fk = {
79	        [Op.in]: divisionCodes,
80	      };
81	    }
82	
83	    const properties = await sql.merchGroup.findAll({
84	      attributes: ['mg_id', 'mg_code', 'mg_desc', 'divisionCode_id_fk', 'parent_id', 'mgCode2', 'mgCategory'],
85	      where: propertyWhereClause,
86	      order: [['mg_desc', 'ASC']],
87	      raw: true,
88	    });
89	
90	    const licensorIds = [...new Set(
91	      properties
92	        .map((property) => property.parent_id)
93	        .filter((parentId) => parentId !== null && parentId !== undefined)
94	    )];
95	
96	    if (!licensorIds.length) {
97	      return result(null, []);
98	    }
99	
100	    const licensors = await sql.merchGroup.findAll({
101	      attributes: ['mg_id', 'mg_code', 'mg_desc', 'divisionCode_id_fk', 'parent_id', 'mgCode2', 'mgCategory'],
102	      where: {
103	        mg_id: {
104	          [Op.in]: licensorIds,
105	        },
106	        mgTypeCode: LICENSOR_MERCH_GROUP_TYPE,
107	      },
108	      order: [['mg_desc', 'ASC']],
109	      raw: true,
110	    });
111	
112	    const propertiesByLicensorId = new Map();
113	
114	    properties.forEach((property) => {
115	      if (property.parent_id === null || property.parent_id === undefined) {
116	        return;
117	      }
118	
119	      const licensorProperties = propertiesByLicensorId.get(property.parent_id) || [];
120	      licensorProperties.push(mapMerchGroupOption(property));
121	      propertiesByLicensorId.set(property.parent_id, licensorProperties);
122	    });
123	
124	    const licensorsWithProperties = licensors
125	      .map((licensor) => ({
126	        ...mapMerchGroupOption(licensor),
127	        properties: propertiesByLicensorId.get(licensor.mg_id) || [],
128	      }))
129	      .filter((licensor) => licensor.properties.length);
130	
131	    result(null, licensorsWithProperties);
132	  } catch (err) {
133	    console.error('Error in getLicensorsWithProperties:', err);
134	    result(err, null);
135	  }
136	};
