138	ItemLibrary.getAllitems = async (req, result) => {
139	  const { startRow, endRow, filterModel } = req.query;
140	  const limit = endRow - startRow;
141	  const offset = Number(startRow);
142	  const isArchive = req.query.isArchive === 'true';
143	
144	  try {
145	    const filters = filterModel ? JSON.parse(filterModel) : {};
146	
147	    // 🔹 Normalize multi filters
148	    Object.keys(filters).forEach(field => {
149	      if (filters[field]?.filterType === 'multi') {
150	        const validSubFilter = filters[field].filterModels.find(sub => sub);
151	        filters[field] = validSubFilter || null;
152	      }
153	    });
154	
155	    const whereClause = {
156	      is_item_active: isArchive ? false : { [Op.or]: ['true', null] }
157	    };
158	
159	    const tagsConditions = [];
160	
161	    const merchGroupFilters = {
162	      merchGroup01: {},
163	      merchGroup02: {},
164	      merchGroup03: {},
165	      merchGroup04: {},
166	      merchGroup05: {},
167	      merchGroup06: {}
168	    };
169	
170	    // 🔹 Utility: Build condition
171	    const buildCondition = (filterDef, dbField) => {
172	      const value = (filterDef && typeof filterDef.filter === 'string') ? filterDef.filter : '';
173	      // Support multi-tag search for 'tags' field: split by comma/space and AND-match all terms
174	      if (dbField === 'tags' && value) {
175	        const terms = value.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
176	        if (terms.length > 1) {
177	          return { [Op.or]: terms.map(t => ({ [Op.iLike]: `%${t}%` })) };
178	        }
179	      }
180	      switch (filterDef.type) {
181	        case 'contains': return { [Op.iLike]: `%${value}%` };
182	        case 'notContains': return { [Op.notILike]: `%${value}%` };
183	        case 'equals': return { [Op.eq]: filterDef.filter };
184	        case 'notEqual': return { [Op.ne]: filterDef.filter };
185	        case 'startsWith': return { [Op.iLike]: `${value}%` };
186	        case 'endsWith': return { [Op.iLike]: `%${value}` };
187	        default: return null;
188	      }
189	    };
190	
191	    const isNonLicFilter = (field, filterDef) => {
192	      const value = String(filterDef?.filter || '').toLowerCase().replace(/[^a-z0-9]/g, '');
193	      return (field === 'licensor' || field === 'property') && value === 'nonlic';
194	    };
195	
196	    // 🔹 Combine division codes and tags conditions properly (AND them together)
197	    const andConditions = [];
198	
199	    // 🔹 Process filters
200	    Object.entries(filters).forEach(([field, filterDef]) => {
201	      if (!filterDef || !filterDef.filter) return;
202	
203	      if (isNonLicFilter(field, filterDef)) {
204	        andConditions.push({ div_code_fk: 9 });
205	        return;
206	      }
207	
208	      const dbField = mapFieldToColumn(field);
209	
210	      // Special handling: tags filter should also search item description (item_descr_name)
211	      if (dbField === 'tags') {
212	        const raw = typeof filterDef.filter === 'string' ? filterDef.filter : String(filterDef.filter || '');
213	        const terms = raw.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
214	        if (terms.length > 0) {
215	          terms.forEach(term => {
216	            tagsConditions.push({
217	              [Op.or]: [
218	                { tags: { [Op.iLike]: `%${term}%` } },
219	                { item_descr_name: { [Op.iLike]: `%${term}%` } }
220	              ]
221	            });
222	          });
223	        }
224	        return; // handled
225	      }
226	
227	      const condition = buildCondition(filterDef, dbField);
228	      if (!condition) return;
229	
230	      // Route to correct merch group or itemHeader
231	      const match = dbField.match(/^merchGroup0([1-6])/);
232	      if (match) {
233	        const key = `merchGroup0${match[1]}`;
234	        merchGroupFilters[key] = condition;
235	      } else {
236	        whereClause[dbField] = condition;
237	      }
238	    });
239	
240	    const divisionCodeIds = req.query.divisionCodeIds ? JSON.parse(req.query.divisionCodeIds) : [];
241	    if (divisionCodeIds.length > 0) {
242	      divisionCodeIds.push(2);
243	      andConditions.push({
244	        [Op.or]: [
245	          { div_code_fk: { [Op.in]: divisionCodeIds } },
246	          { div_code_fk: null }
247	        ]
248	      });
249	    }
250	
251	    if (tagsConditions.length > 0) {
252	      andConditions.push({
253	        [Op.or]: tagsConditions
254	      });
255	    }
256	
257	    if (andConditions.length > 0) {
258	      whereClause[Op.and] = andConditions;
259	    }
260	
261	    // 🔹 Helper: Generate merchGroup includes
262	    const generateMerchGroupIncludes = () => {
263	      return Object.entries(merchGroupFilters).map(([key, filter]) => {
264	        const match = key.match(/^merchGroup0([1-6])/);
265	        const hasFilter = Reflect.ownKeys(filter).length > 0;
266	        return {
267	          model: sql.merchGroup,
268	          as: key,
269	          required: hasFilter,
270	          where: hasFilter ? { mgTypeCode: `0${match[1]}`, mg_desc: filter, divisionCode_id_fk: divisionCodeIds } : undefined
271	        }
272	    }
273	    );
274	    };
275	
276	    const merchIncludes = generateMerchGroupIncludes();
277	
278	    // 🔹 Query 1: Accurate Count
279	    const count = await sql.itemHeader.count({
280	      where: whereClause,
281	      include: merchIncludes,
282	      distinct: true,
283	      col: 'item_id_pk'
284	    });
285	
286	    // 🔹 Query 2: Actual paginated rows
287	    const rows = await sql.itemHeader.findAll({
288	      logging: console.log,
289	      attributes: [
290	        'item_id_pk', 'div_code_fk', 'created_time_date',
291	        'item_active_status', 'item_descr_name',
292	        'udf_merchgroup01', 'udf_merchgroup01_id',
293	        'udf_merchgroup02', 'udf_merchgroup02_id',
294	        'udf_merchgroup03', 'udf_merchgroup03_id',
295	        'udf_merchgroup04', 'udf_merchgroup04_id',
296	        'udf_merchgroup05_fk', 'udf_merchgroup05_fk_id',
297	        'udf_merchgroup06_fk', 'udf_merchgroup06_fk_id',
298	        'udf_merchgroup07_fk', 'udf_merchgroup07_fk_id',
299	        'udf_merchgroup08_fk', 'udf_merchgroup08_fk_id',
300	        'udf_merchgroup09_fk', 'udf_merchgroup09_fk_id',
301	        'udf_merchgroup10_fk', 'udf_merchgroup10_fk_id',
302	        'season_code_fk', 'season_code_fk_id', 'tags',
303	        'vendor_code_fk', 'item_num_id', 'ref_num',
304	        'is_item_active', 'is_item_old'
305	      ],
306	      where: whereClause,
307	      order: [
308	        ['item_id_pk', 'DESC'],
309	        ['created_time_date', 'DESC'],
310	        [{ model: sql.itemAttachment, as: 'itemAttachments' }, 'item_num_id_fk', 'ASC'],
311	        [{ model: sql.itemAttachment, as: 'itemAttachments' }, 'attachment_display_name', 'ASC']
312	      ],
313	      limit,
314	      offset,
315	      include: [
316	        {
317	          model: sql.itemAttachment,
318	          as: 'itemAttachments'
319	        },
320	        ...merchIncludes
321	      ]
322	    });
323	
324	    const colHeaders = await getGridHeader(['itemLibrary']);
325	    const remappedData = await utility.remapProdItem(colHeaders, rows);
326	
327	    result(null, {
328	      rows: remappedData,
329	      totalCount: count
330	    });
331	
332	  } catch (err) {
333	    console.error('Error in getAllitems:', err);
334	    result(null, err);
335	  }
336	};
