338	ItemLibrary.getApiAllItems = async (req, result) => {
339	  try {
340	    const isArchive = req.query.isArchive === 'true';
341	
342	    const whereClause = {
343	      is_item_active: isArchive ? false : { [Op.or]: ['true', null] }
344	    };
345	
346	    const divisionCodeIds = req.query.divisionCodeIds ? JSON.parse(req.query.divisionCodeIds) : [];
347	    const andConditions = [];
348	
349	    if (divisionCodeIds.length > 0) {
350	      divisionCodeIds.push(2);
351	      andConditions.push({
352	        [Op.or]: [
353	          { div_code_fk: { [Op.in]: divisionCodeIds } },
354	          { div_code_fk: null }
355	        ]
356	      });
357	    }
358	
359	    if (req.query.startDate || req.query.endDate) {
