385	        'udf_merchgroup03', 'udf_merchgroup03_id',
386	        'udf_merchgroup04', 'udf_merchgroup04_id',
387	        'udf_merchgroup05_fk', 'udf_merchgroup05_fk_id',
388	        'udf_merchgroup06_fk', 'udf_merchgroup06_fk_id',
389	        'udf_merchgroup07_fk', 'udf_merchgroup07_fk_id',
390	        'udf_merchgroup08_fk', 'udf_merchgroup08_fk_id',
391	        'udf_merchgroup09_fk', 'udf_merchgroup09_fk_id',
392	        'udf_merchgroup10_fk', 'udf_merchgroup10_fk_id',
393	        'season_code_fk', 'season_code_fk_id', 'tags',
394	        'vendor_code_fk', 'item_num_id', 'ref_num',
395	        'is_item_active', 'is_item_old'
396	      ],
397	      where: whereClause,
398	      order: [
399	        ['item_id_pk', 'DESC'],
400	        ['created_time_date', 'DESC'],
401	        [{ model: sql.itemAttachment, as: 'itemAttachments' }, 'item_num_id_fk', 'ASC'],
402	        [{ model: sql.itemAttachment, as: 'itemAttachments' }, 'attachment_display_name', 'ASC']
403	      ],
404	      include: [
405	        {
406	          model: sql.itemAttachment,
407	          as: 'itemAttachments'
408	        },
409	        {
410	          model: sql.ProdOrderDetail,
411	          as: 'prodOrderDetails',
412	          required: false,
413	          separate: true,
414	          attributes: ['itemNo', 'prepackCode', 'pkey', 'prodOrderNo']
415	        },
416	        { model: sql.merchGroup, as: 'merchGroup01', required: false },
417	        { model: sql.merchGroup, as: 'merchGroup02', required: false },
418	        { model: sql.merchGroup, as: 'merchGroup03', required: false },
419	        { model: sql.merchGroup, as: 'merchGroup04', required: false },
420	        { model: sql.merchGroup, as: 'merchGroup05', required: false },
421	        { model: sql.merchGroup, as: 'merchGroup06', required: false }
422	      ]
423	    });
424	
425	    const colHeaders = await getGridHeader(['itemLibrary']);
426	    const remappedData = await utility.getApiAllItems(colHeaders, rows);
427	
428	    result(null, {
429	      rows: remappedData,
