647	ItemLibrary.searchItemTypes = async (req, result) => {
648	  try {
649	    const query = String(req.query.q || '').trim();
650	    const whereClause = buildItemTypeSearchWhereClause(query);
651	    let itemTypes = await sql.itemType.findAll({
652	      attributes: ITEM_TYPE_SEARCH_ATTRIBUTES,
653	      where: whereClause,
654	      order: [['item_type_name', 'ASC']],
655	      limit: ITEM_TYPE_SEARCH_LIMIT
656	    });
657	
658	    let candidates = itemTypes.map((itemType) => itemType.toJSON());
659	
660	    if (query) {
661	      candidates = candidates.sort((left, right) => {
662	        const scoreDifference = scoreItemTypeCandidate(right, query) - scoreItemTypeCandidate(left, query);
663	        if (scoreDifference !== 0) {
664	          return scoreDifference;
665	        }
666	
667	        return (left?.item_type_name || '').localeCompare(right?.item_type_name || '');
668	      });
669	    }
670	
671	    result(null, candidates.slice(0, ITEM_TYPE_SEARCH_LIMIT));
672	  } catch (err) {
673	    result(null, err);
674	  }
