83	function formatOrdinalDate(dateValue) {
84	  if (!dateValue) return null;
85	  try {
86	    let d = new Date(dateValue);
87	    if (typeof dateValue === 'string' && dateValue.includes('-') && !dateValue.includes('T')) {
88	      const [year, month, day] = dateValue.split('-');
89	      d = new Date(Number(year), Number(month) - 1, Number(day));
90	    }
91	    if (Number.isNaN(d.getTime())) return null;
92	
93	    const day = d.getDate();
94	    const suffix = [, 'st', 'nd', 'rd'][day % 10 > 3 ? 0 : (day % 100 - day % 10 !== 10) * (day % 10)] || 'th';
95	    const month = d.toLocaleString('en-US', { month: 'short' });
96	    const year = String(d.getFullYear()).slice(-2);
97	    return `${day}${suffix} ${month} ${year}`;
98	  } catch (error) {
99	    return null;
100	  }
101	}
