107	    return new Date(date.getFullYear(), date.getMonth(), date.getDate());
108	  };
109	
110	  const actualDay = toDay(actual);
111	  const estimateDay = toDay(estimate);
112	  return !!(actualDay && estimateDay && actualDay > estimateDay);
113	}
