251	  const ppsEstStart = ppsStartDate || fallbackPpsStart;
252	
253	  if (ppsEstStart) {
254	    const estCompletion = addDays(ppsEstStart, ppsDays);
255	    const completionDate = ppsCompletionDate;
256	    const ppsEvents = sorted.filter(status => isPpsStatus(status.status)).map(toStageEvent);
257	    let statusLabel = ppsStartDate ? 'In Progress' : 'Pending';
258	
259	    if (completionDate) {
260	      statusLabel = ppsApprovedEntry.status === 'Pre-pro approved with Changes' ? 'Approved with Changes' : 'Approved';
261	    } else if (sorted.some(status => status.status === 'Pre-pro Rejected' || status.status === 'Pre-Pro Rejected')) {
262	      statusLabel = 'Rejected - Resubmit';
263	    } else if (sorted.some(status => status.status === 'Pre-pro Needs Revisions')) {
264	      statusLabel = 'Needs Revisions';
265	    }
266	
267	    rows.push({
268	      phase: 'PPS Approval',
269	      status: statusLabel,
270	      date: formatOrdinalDate(ppsStartDate),
271	      completionDate: formatOrdinalDate(completionDate),
272	      _rawCompletionDate: completionDate,
273	      estStartDate: formatOrdinalDate(ppsEstStart),
274	      estCompletionDate: formatOrdinalDate(estCompletion),
275	      _rawEstCompletionDate: estCompletion,
276	      neededDate: formatOrdinalDate(ppsNeededDate),
277	      detailLines: getDetailLines(licTimes, 'PPS approval duration', ppsDays),
278	      events: ppsEvents,
279	      isDelayed: ppsNeededDate
280	        ? (completionDate ? isAfterDay(completionDate, ppsNeededDate) : isAfterDay(new Date(), ppsNeededDate))
281	        : false
282	    });
283	  }
284	
285	  return rows;
286	}
