325	    where: {
326	      itemheader_id_fk: itemId,
327	      package: false
328	    }
329	  });
330	  const licensorGroups = item.udf_merchgroup05_fk
331	    ? await sql.merchGroup.findAll({
332	        attributes: ['mg_desc'],
333	        where: { mg_code: item.udf_merchgroup05_fk }
334	      })
335	    : [];
336	  const licensingTimes = await getLicensingTimes(sql);
