344	  return {
345	    itemId,
346	    itemNumber: item.item_num_id || null,
347	    neededDate,
348	    stages: buildStageRows(plainStatuses, licTimes, neededDate),
349	    history: buildHistoricalStageRows(plainStatuses)
350	  };
