822	function isLicensingImageAttachment(attachment) {
823	  const type = String(attachment?.type || '').toLowerCase();
824	  const name = String(attachment?.name || '').toLowerCase();
825	  const link = String(attachment?.link || attachment?.url || '').toLowerCase();
826	  if (type.startsWith('image/')) return true;
827	  return /\.(png|jpe?g|gif|webp|bmp|svg)(\?.*)?$/i.test(name)
828	    || /\.(png|jpe?g|gif|webp|bmp|svg)(\?.*)?$/i.test(link);
829	}
