1238	// ─── Item Type Search Helpers ────────────────────────────────────────────────
1239	
1240	exports.normalizeSearchTerm = (value = '') =>
1241	  value.toLowerCase().trim().replace(/\s+/g, ' ');
1242	
1243	exports.getItemTypeSearchTerms = (query = '') => {
1244	  const normalized = exports.normalizeSearchTerm(query);
1245	  const tokens = normalized.split(/\s+/).filter(Boolean);
1246	  return Array.from(new Set([normalized, ...tokens].filter(Boolean)));
1247	};
1248	
1249	/**
1250	 * Levenshtein edit distance between two strings.
1251	 * Lower = more similar. Used for fuzzy/typo-tolerant matching.
1252	 */
1253	const levenshteinDistance = (a, b) => {
1254	  const m = a.length;
1255	  const n = b.length;
1256	  const dp = Array.from({ length: m + 1 }, (_, i) =>
1257	    Array.from({ length: n + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0))
1258	  );
1259	  for (let i = 1; i <= m; i++) {
1260	    for (let j = 1; j <= n; j++) {
1261	      dp[i][j] = a[i - 1] === b[j - 1]
1262	        ? dp[i - 1][j - 1]
1263	        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
1264	    }
1265	  }
1266	  return dp[m][n];
1267	};
1268	
1269	/**
1270	 * Returns a 0–1 similarity ratio based on edit distance.
1271	 */
1272	const stringSimilarity = (a, b) => {
1273	  if (!a || !b) return 0;
1274	  const maxLen = Math.max(a.length, b.length);
1275	  return maxLen === 0 ? 1 : 1 - levenshteinDistance(a, b) / maxLen;
1276	};
1277	
1278	/**
1279	 * Scores a DB candidate against the search query.
1280	 * Combines exact/prefix/contains rules with fuzzy similarity so
1281	 * near-matches and slight misspellings still rank well.
1282	 */
1283	exports.scoreItemTypeCandidate = (candidate, query) => {
1284	  const normalizedQuery = exports.normalizeSearchTerm(query);
1285	  const candidateName = exports.normalizeSearchTerm(candidate?.item_type_name || '');
1286	  const candidateDescription = exports.normalizeSearchTerm(candidate?.item_type_description || '');
1287	  const queryTerms = exports.getItemTypeSearchTerms(query);
1288	
1289	  if (!normalizedQuery) return 0;
1290	
1291	  let score = 0;
1292	
1293	  // Exact / prefix / substring matches on full query
1294	  if (candidateName === normalizedQuery) score += 120;
1295	  if (candidateName.startsWith(normalizedQuery)) score += 80;
1296	  if (candidateName.includes(normalizedQuery)) score += 50;
1297	  if (candidateDescription.includes(normalizedQuery)) score += 25;
1298	
1299	  // Token-level substring matches
1300	  queryTerms.forEach((term) => {
1301	    if (candidateName.startsWith(term)) score += 18;
1302	    if (candidateName.includes(term)) score += 10;
1303	    if (candidateDescription.includes(term)) score += 6;
1304	  });
1305	
1306	  // Fuzzy similarity — catches typos and near-matches
1307	  const nameSimilarity = stringSimilarity(candidateName, normalizedQuery);
1308	  score += Math.round(nameSimilarity * 40);
1309	
1310	  // Also score each query token against each word in the candidate name
1311	  const nameWords = candidateName.split(/\s+/).filter(Boolean);
1312	  queryTerms.forEach((term) => {
1313	    const bestWordSimilarity = Math.max(
1314	      0,
1315	      ...nameWords.map((word) => stringSimilarity(word, term))
1316	    );
1317	    if (bestWordSimilarity >= 0.75) {
1318	      score += Math.round(bestWordSimilarity * 20);
1319	    }
1320	  });
1321	
1322	  return score;
1323	};
